59: impl Representative {
60:     pub(crate) fn rvid(self) -> RegionVid {
61:         match self {
62:             Representative::FreeRegion(region_vid)
63:             | Representative::Placeholder(region_vid)
64:             | Representative::Existential(region_vid) => region_vid,
65:         }
